/*\n  # Optimize Remaining RLS Policies - Part 1\n  \n  ## Overview\n  Continues RLS policy optimization by replacing auth.uid() with (SELECT auth.uid())\n  for improved performance at scale.\n  \n  ## Tables Optimized (Part 1 of 4)\n  - user_profiles (6 policies)\n  - linkedin_profile_optimizations (4 policies)\n  - portfolio_data (6 policies)\n  - portfolio_templates (6 policies)\n  - portfolio_deployments (5 policies)\n  - ai_job_recommendations (3 policies)\n  - user_job_preferences (4 policies)\n  - wallet_transactions (2 policies)\n  - survey_subscriptions (3 policies)\n  - survey_payment_transactions (2 policies)\n  - user_addon_credits (2 policies)\n  - mock_interview_sessions (4 policies)\n  - interview_questions (2 policies)\n  - interview_responses (4 policies)\n*/\n\n-- ============================================================================\n-- USER_PROFILES TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can read own profile" ON public.user_profiles;
\nDROP POLICY IF EXISTS "Users can update own profile" ON public.user_profiles;
\nDROP POLICY IF EXISTS "Users can insert own profile" ON public.user_profiles;
\nDROP POLICY IF EXISTS "Admins can read all profiles" ON public.user_profiles;
\nDROP POLICY IF EXISTS "Admins can update all profiles" ON public.user_profiles;
\nDROP POLICY IF EXISTS "Admins can insert profiles" ON public.user_profiles;
\n\nCREATE POLICY "Users can read own profile" ON public.user_profiles\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = id);
\n\nCREATE POLICY "Users can update own profile" ON public.user_profiles\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = id)\n  WITH CHECK ((SELECT auth.uid()) = id);
\n\nCREATE POLICY "Users can insert own profile" ON public.user_profiles\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = id);
\n\nCREATE POLICY "Admins can read all profiles" ON public.user_profiles\n  FOR SELECT TO authenticated\n  USING (is_admin((SELECT auth.uid())));
\n\nCREATE POLICY "Admins can update all profiles" ON public.user_profiles\n  FOR UPDATE TO authenticated\n  USING (is_admin((SELECT auth.uid())))\n  WITH CHECK (is_admin((SELECT auth.uid())));
\n\nCREATE POLICY "Admins can insert profiles" ON public.user_profiles\n  FOR INSERT TO authenticated\n  WITH CHECK (is_admin((SELECT auth.uid())));
\n\n-- ============================================================================\n-- LINKEDIN_PROFILE_OPTIMIZATIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can read own linkedin profile optimizations" ON public.linkedin_profile_optimizations;
\nDROP POLICY IF EXISTS "Users can create linkedin profile optimizations" ON public.linkedin_profile_optimizations;
\nDROP POLICY IF EXISTS "Users can update own linkedin profile optimizations" ON public.linkedin_profile_optimizations;
\nDROP POLICY IF EXISTS "Users can delete own linkedin profile optimizations" ON public.linkedin_profile_optimizations;
\n\nCREATE POLICY "Users can read own linkedin profile optimizations" ON public.linkedin_profile_optimizations\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can create linkedin profile optimizations" ON public.linkedin_profile_optimizations\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own linkedin profile optimizations" ON public.linkedin_profile_optimizations\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can delete own linkedin profile optimizations" ON public.linkedin_profile_optimizations\n  FOR DELETE TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\n-- ============================================================================\n-- PORTFOLIO_DATA TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own portfolio data" ON public.portfolio_data;
\nDROP POLICY IF EXISTS "Users can insert own portfolio data" ON public.portfolio_data;
\nDROP POLICY IF EXISTS "Users can update own portfolio data" ON public.portfolio_data;
\nDROP POLICY IF EXISTS "Users can delete own portfolio data" ON public.portfolio_data;
\nDROP POLICY IF EXISTS "Admins can view all portfolio data" ON public.portfolio_data;
\n\nCREATE POLICY "Users can view own portfolio data" ON public.portfolio_data\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can insert own portfolio data" ON public.portfolio_data\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own portfolio data" ON public.portfolio_data\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can delete own portfolio data" ON public.portfolio_data\n  FOR DELETE TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Admins can view all portfolio data" ON public.portfolio_data\n  FOR SELECT TO authenticated\n  USING (is_admin((SELECT auth.uid())));
