\n\nCREATE POLICY "Users can view own templates" ON public.portfolio_templates\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can insert own templates" ON public.portfolio_templates\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own templates" ON public.portfolio_templates\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can delete own templates" ON public.portfolio_templates\n  FOR DELETE TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
