\n\n-- ============================================================================\n-- PORTFOLIO_DEPLOYMENTS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own deployments" ON public.portfolio_deployments;
\nDROP POLICY IF EXISTS "Users can insert own deployments" ON public.portfolio_deployments;
