\n\nCREATE POLICY "Users can insert own deployments" ON public.portfolio_deployments\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own deployments" ON public.portfolio_deployments\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can delete own deployments" ON public.portfolio_deployments\n  FOR DELETE TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
