\n\nCREATE POLICY "Admins can view all recommendations" ON public.ai_job_recommendations\n  FOR SELECT TO authenticated\n  USING (is_admin((SELECT auth.uid())));
\n\n-- ============================================================================\n-- USER_JOB_PREFERENCES TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own preferences" ON public.user_job_preferences;
\nDROP POLICY IF EXISTS "Users can insert own preferences" ON public.user_job_preferences;
\nDROP POLICY IF EXISTS "Users can update own preferences" ON public.user_job_preferences;
\nDROP POLICY IF EXISTS "Users can delete own preferences" ON public.user_job_preferences;
\n\nCREATE POLICY "Users can view own preferences" ON public.user_job_preferences\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can insert own preferences" ON public.user_job_preferences\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own preferences" ON public.user_job_preferences\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
