\n\n-- ============================================================================\n-- WALLET_TRANSACTIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view their own wallet transactions" ON public.wallet_transactions;
\nDROP POLICY IF EXISTS "System can insert transactions" ON public.wallet_transactions;
\n\nCREATE POLICY "Users can view their own wallet transactions" ON public.wallet_transactions\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id OR (SELECT auth.uid()) = source_user_id);
\n\nCREATE POLICY "System can insert transactions" ON public.wallet_transactions\n  FOR INSERT TO authenticated\n  WITH CHECK (true);
\n\n-- ============================================================================\n-- SURVEY_SUBSCRIPTIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own survey subscriptions" ON public.survey_subscriptions;
\nDROP POLICY IF EXISTS "Users can create own survey subscriptions" ON public.survey_subscriptions;
\nDROP POLICY IF EXISTS "Users can update own survey subscriptions" ON public.survey_subscriptions;
\n\nCREATE POLICY "Users can view own survey subscriptions" ON public.survey_subscriptions\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can create own survey subscriptions" ON public.survey_subscriptions\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own survey subscriptions" ON public.survey_subscriptions\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\n-- ============================================================================\n-- SURVEY_PAYMENT_TRANSACTIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own survey transactions" ON public.survey_payment_transactions;
\nDROP POLICY IF EXISTS "Users can create own survey transactions" ON public.survey_payment_transactions;
\n\nCREATE POLICY "Users can view own survey transactions" ON public.survey_payment_transactions\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
