\n\n-- ============================================================================\n-- USER_ADDON_CREDITS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view their own add-on credits" ON public.user_addon_credits;
\nDROP POLICY IF EXISTS "Users can update their own add-on credits" ON public.user_addon_credits;
\n\nCREATE POLICY "Users can view their own add-on credits" ON public.user_addon_credits\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update their own add-on credits" ON public.user_addon_credits\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\n-- ============================================================================\n-- MOCK_INTERVIEW_SESSIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own interview sessions" ON public.mock_interview_sessions;
\nDROP POLICY IF EXISTS "Users can create own interview sessions" ON public.mock_interview_sessions;
\nDROP POLICY IF EXISTS "Users can update own interview sessions" ON public.mock_interview_sessions;
\nDROP POLICY IF EXISTS "Admins can view all interview sessions" ON public.mock_interview_sessions;
\n\nCREATE POLICY "Users can view own interview sessions" ON public.mock_interview_sessions\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can create own interview sessions" ON public.mock_interview_sessions\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own interview sessions" ON public.mock_interview_sessions\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Admins can view all interview sessions" ON public.mock_interview_sessions\n  FOR SELECT TO authenticated\n  USING (is_admin((SELECT auth.uid())));
\n\n-- ============================================================================\n-- INTERVIEW_QUESTIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Admins can insert interview questions" ON public.interview_questions;
\nDROP POLICY IF EXISTS "Admins can update interview questions" ON public.interview_questions;
\n\nCREATE POLICY "Admins can insert interview questions" ON public.interview_questions\n  FOR INSERT TO authenticated\n  WITH CHECK (is_admin((SELECT auth.uid())));
\n\nCREATE POLICY "Admins can update interview questions" ON public.interview_questions\n  FOR UPDATE TO authenticated\n  USING (is_admin((SELECT auth.uid())))\n  WITH CHECK (is_admin((SELECT auth.uid())));
\n\n-- ============================================================================\n-- INTERVIEW_RESPONSES TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own interview responses" ON public.interview_responses;
\nDROP POLICY IF EXISTS "Users can create own interview responses" ON public.interview_responses;
\nDROP POLICY IF EXISTS "Users can update own interview responses" ON public.interview_responses;
\nDROP POLICY IF EXISTS "Admins can view all interview responses" ON public.interview_responses;
\n\nCREATE POLICY "Users can view own interview responses" ON public.interview_responses\n  FOR SELECT TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.mock_interview_sessions\n    WHERE mock_interview_sessions.id = interview_responses.session_id\n    AND mock_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\nCREATE POLICY "Users can create own interview responses" ON public.interview_responses\n  FOR INSERT TO authenticated\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.mock_interview_sessions\n    WHERE mock_interview_sessions.id = interview_responses.session_id\n    AND mock_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\nCREATE POLICY "Users can update own interview responses" ON public.interview_responses\n  FOR UPDATE TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.mock_interview_sessions\n    WHERE mock_interview_sessions.id = interview_responses.session_id\n    AND mock_interview_sessions.user_id = (SELECT auth.uid())\n  ))\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.mock_interview_sessions\n    WHERE mock_interview_sessions.id = interview_responses.session_id\n    AND mock_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\nCREATE POLICY "Admins can view all interview responses" ON public.interview_responses\n  FOR SELECT TO authenticated\n  USING (is_admin((SELECT auth.uid())));
\n;
